-- Prompt 29 owner metadata, idempotent webhook queue and dead-letter lifecycle.
begin;set local role service_role;select set_config('request.jwt.claim.role','service_role',true);
insert into public.integration_connections(id,gym_id,provider_key,provider_category,status,encrypted_configuration,configuration_fingerprint,created_by)values('9a000000-0000-4000-8000-000000000001','30000000-0000-4000-8000-000000000001','check_in_placeholder','check_in','active','enc:v1:ciphertext','aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa','10000000-0000-4000-8000-000000000001');
do $$declare first_id uuid;second_id uuid;begin first_id:=public.ingest_integration_delivery('9a000000-0000-4000-8000-000000000001','check_in_placeholder','event-1','{"kind":"arrival"}');second_id:=public.ingest_integration_delivery('9a000000-0000-4000-8000-000000000001','check_in_placeholder','event-1','{"kind":"arrival"}');if first_id<>second_id or(select count(*)from public.integration_deliveries where integration_id='9a000000-0000-4000-8000-000000000001'and idempotency_key='event-1')<>1 then raise exception'Webhook idempotency failed';end if;perform set_config('test.delivery',first_id::text,true);for attempt in 1..5 loop perform public.record_integration_delivery_attempt(first_id,false,'timeout');end loop;if(select status from public.integration_deliveries where id=first_id)<>'dead_letter'or(select status from public.integration_connections where id='9a000000-0000-4000-8000-000000000001')<>'error'then raise exception'Dead letter lifecycle failed';end if;end$$;
set local role authenticated;select set_config('request.jwt.claim.role','authenticated',true);select set_config('request.jwt.claim.sub','10000000-0000-4000-8000-000000000004',true);do $$begin if exists(select 1 from public.get_integration_statuses('30000000-0000-4000-8000-000000000001'))then raise exception'Member saw integration status';end if;begin perform*from public.integration_connections;raise exception'Member read encrypted configuration';exception when insufficient_privilege then null;end;end$$;
select set_config('request.jwt.claim.sub','10000000-0000-4000-8000-000000000001',true);do $$declare status_row record;begin select*into status_row from public.get_integration_statuses('30000000-0000-4000-8000-000000000001')where provider_key='check_in_placeholder';if status_row.status<>'error'or status_row.dead_letter<>1 then raise exception'Owner status did not reconcile';end if;if pg_get_function_result('public.get_integration_statuses(uuid)'::regprocedure)~'(encrypted|payload|fingerprint)'then raise exception'Status RPC exposes secret fields';end if;end$$;
rollback;
